```holoscript
scene PhysicsDemo {

  object Ramp @collidable {
    geometry: 'box'
    position: [0, 1, 0]
    rotation: [-30, 0, 0]
    scale: [4, 0.2, 8]
    color: '#A08855'
  }

  // Balls at top of ramp
  repeat 10 as i {
    object Ball_{i} @grabbable @throwable {
      geometry: 'sphere'
      position: [-1.8 + i * 0.4, 2.6, -3.5]
      scale: 0.26
      color: '#10C8AB'
      physics: { mass: 1, restitution: 0.88, enabled: false }
    }
  }

  // Bowling pin positions
  object Pin1 @collidable { geometry: 'cylinder' position: [0, 1.13, 4.4] scale: [0.14, 0.38, 0.14] color: '#FFFFFF' physics: { mass: 0.6 } }
  object Pin2 @collidable { geometry: 'cylinder' position: [-0.3, 1.13, 4.7] scale: [0.14, 0.38, 0.14] color: '#FFFFFF' physics: { mass: 0.6 } }
  object Pin3 @collidable { geometry: 'cylinder' position: [0.3, 1.13, 4.7] scale: [0.14, 0.38, 0.14] color: '#FFFFFF' physics: { mass: 0.6 } }
  object Pin4 @collidable { geometry: 'cylinder' position: [-0.6, 1.13, 5.0] scale: [0.14, 0.38, 0.14] color: '#FFFFFF' physics: { mass: 0.6 } }
  object Pin5 @collidable { geometry: 'cylinder' position: [0, 1.13, 5.0] scale: [0.14, 0.38, 0.14] color: '#FFFFFF' physics: { mass: 0.6 } }
  object Pin6 @collidable { geometry: 'cylinder' position: [0.6, 1.13, 5.0] scale: [0.14, 0.38, 0.14] color: '#FFFFFF' physics: { mass: 0.6 } }

  // Release button
  ui ReleaseButton {
    type: 'button'
    position: [0.9, 3.1, -3.3]
    size: [0.35, 0.15]
    text: 'Release Balls'
    style: { background: '#2222AA', textColor: '#FFFFFF' }

    on click {
      repeat 10 as i {
        set Ball_{i}.physics.enabled: true
      }
    }
  }

  // Reset button
  ui ResetButton {
    type: 'button'
    position: [-1.3, 3.1, -3.3]
    size: [0.35, 0.15]
    text: 'Reset Demo'
    style: { background: '#CC3333', textColor: '#FFFFFF' }

    on click {
      repeat 10 as i {
        set Ball_{i}.physics.enabled: false
        set Ball_{i}.position: [-1.8 + i * 0.4, 2.6, -3.5]
        set Ball_{i}.velocity: [0, 0, 0]
      }
    }
  }
}
```

This creates a bowling-style physics demo with 10 balls on a ramp, 6 pins in formation, and buttons to release and reset.

