```holoscript
scene PuzzleRoom {

  state sequence: []
  state solved: false
  const correctOrder: ['blue', 'red', 'green']

  // Room lighting
  light RoomLight {
    type: 'ambient'
    color: '#FFFFFF'
    intensity: 0.5
  }

  // Hint text
  text HintText {
    content: 'The sky comes first...'
    position: [0, 3.5, -4]
    color: '#AACCFF'
    fontSize: 32
    align: 'center'

    animation Float {
      property: 'position.y'
      from: 3.4
      to: 3.6
      duration: 2s
      loop: infinite
      direction: alternate
    }
  }

  // Blue button pedestal
  object PedestalBlue @collidable {
    geometry: 'cylinder'
    position: [-2, 0.5, -2]
    scale: [0.5, 1, 0.5]
    color: '#333333'
  }

  object ButtonBlue @interactable {
    geometry: 'sphere'
    position: [-2, 1.3, -2]
    scale: 0.3
    color: '#4488FF'
    emissive: '#224488'

    on click {
      if not solved {
        play sound 'chime_blue.mp3'
        animate emissive to '#88CCFF' duration: 0.2s then '#224488'
        push 'blue' to sequence
        call CheckSequence
      }
    }
  }

  // Red button pedestal
  object PedestalRed @collidable {
    geometry: 'cylinder'
    position: [0, 0.5, -2]
    scale: [0.5, 1, 0.5]
    color: '#333333'
  }

  object ButtonRed @interactable {
    geometry: 'sphere'
    position: [0, 1.3, -2]
    scale: 0.3
    color: '#FF4444'
    emissive: '#882222'

    on click {
      if not solved {
        play sound 'chime_red.mp3'
        animate emissive to '#FF8888' duration: 0.2s then '#882222'
        push 'red' to sequence
        call CheckSequence
      }
    }
  }

  // Green button pedestal
  object PedestalGreen @collidable {
    geometry: 'cylinder'
    position: [2, 0.5, -2]
    scale: [0.5, 1, 0.5]
    color: '#333333'
  }

  object ButtonGreen @interactable {
    geometry: 'sphere'
    position: [2, 1.3, -2]
    scale: 0.3
    color: '#44FF44'
    emissive: '#228822'

    on click {
      if not solved {
        play sound 'chime_green.mp3'
        animate emissive to '#88FF88' duration: 0.2s then '#228822'
        push 'green' to sequence
        call CheckSequence
      }
    }
  }

  // Large door
  object Door @collidable {
    geometry: 'box'
    position: [0, 2, -5]
    scale: [3, 4, 0.3]
    color: '#8B4513'

    animation Open {
      property: 'position.x'
      to: -3
      duration: 1.5s
      easing: 'easeInOut'
    }
  }

  // Error flash overlay
  object ErrorFlash {
    geometry: 'plane'
    position: [0, 2, 0]
    scale: 20
    color: '#FF0000'
    opacity: 0

    animation Flash {
      property: 'opacity'
      keyframes: [0, 0.5, 0]
      duration: 0.5s
    }
  }

  // Sequence checker
  function CheckSequence {
    // Check if sequence matches so far
    let valid: true
    repeat sequence.length as i {
      if sequence[i] != correctOrder[i] {
        set valid: false
      }
    }

    if not valid {
      // Wrong sequence
      play sound 'buzzer.mp3'
      play ErrorFlash.Flash
      set sequence: []
    } else if sequence.length == 3 {
      // Correct sequence complete!
      set solved: true
      play sound 'success.mp3'
      play Door.Open
      set HintText.content: 'Well done!'
      set HintText.color: '#44FF44'
    }
  }
}
```

This creates a puzzle room with three color-coded buttons on pedestals. Players must press blue, red, then green (following the "sky comes first" hint). Each button glows and chimes when pressed. Wrong order triggers a buzzer and red flash. Correct order slides the door open with a success sound.

```holoscript
object GuardNPC @networked @collidable {
  model: 'guard.glb'
  position: [0, 0, 0]
  scale: 1

  state patrolIndex: 0
  state isGreeting: false

  const patrolPoints: [
    [0, 0, 0],
    [5, 0, 0],
    [5, 0, 5],
    [0, 0, 5]
  ]

  animation Walk {
    clip: 'walk'
    loop: true
  }

  animation Idle {
    clip: 'idle'
    loop: true
  }

  animation Wave {
    clip: 'wave'
    loop: false
  }

  // Patrol behavior
  on interval 3s {
    if not isGreeting {
      set patrolIndex: (patrolIndex + 1) % 4
      let target: patrolPoints[patrolIndex]

      look at target
      play Walk
      animate position to target duration: 2.5s easing: 'linear'
    }
  }

  // Greeting trigger zone
  trigger GreetingZone {
    shape: 'sphere'
    radius: 3

    on enter by player {
      if not isGreeting {
        set isGreeting: true
        stop animation Walk
        look at player
        play Wave

        speech Greeting {
          text: 'Hello there, traveler!'
          duration: 3s
          style: { bubble: true, color: '#FFFFFF' }
        }

        after 3s {
          set isGreeting: false
          play Walk
        }
      }
    }
  }
}
```

This creates an NPC guard that patrols a square path, stopping to wave and greet players who come within 3 meters, then resumes patrol.

