scene RaceTrack @networked {

  state raceStarted: false
  state raceTime: 0
  state checkpointsPassed: 0
  state bestTime: null

  const totalCheckpoints: 5

  // Timer UI
  ui TimerDisplay {
    position: [0, 3, -2]
    size: [1.5, 0.4]
    anchor: 'top'
    style: { background: '#000000AA', borderRadius: 8 }

    text Timer {
      content: '⏱️ {formatTime(raceTime)}'
      fontSize: 32
      color: '#00FF00'
      align: 'center'
    }

    text Checkpoints {
      content: '🚩 {checkpointsPassed}/{totalCheckpoints}'
      position: [0, -0.15, 0]
      fontSize: 18
      color: '#FFFFFF'
    }
  }

  // Best time display
  ui BestTimeDisplay {
    position: [1.5, 3, -2]
    size: [1, 0.3]
    style: { background: '#FFD70044', borderRadius: 6 }
    visible: bestTime != null

    text BestLabel {
      content: '🏆 Best: {formatTime(bestTime)}'
      fontSize: 18
      color: '#FFD700'
    }
  }

  // Start line
  object StartLine @trigger {
    geometry: 'box'
    position: [0, 0.05, 0]
    scale: [5, 0.1, 0.5]
    color: '#FFFFFF'

    // Checkered pattern
    texture: 'checkered.png'

    on enter by player {
      if not raceStarted {
        set raceStarted: true
        set raceTime: 0
        set checkpointsPassed: 0
        play sound 'race_start.mp3'
        notify player '🏁 Race started! Go!'

        // Start timer
        start timer RaceTimer interval: 0.01s {
          set raceTime: raceTime + 0.01
        }
      }
    }
  }

  // Checkpoint 1
  object Checkpoint1 @trigger {
    geometry: 'torus'
    position: [15, 2, 10]
    rotation: [90, 0, 0]
    scale: [3, 3, 0.3]
    color: '#FFAA00'
    emissive: '#FF6600'

    state passed: false

    on enter by player {
      if raceStarted and not passed {
        set passed: true
